import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Random Image API و Public Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Other/random-image-api-and-public-gallery.md","filePath":"fa/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),i={name:"fa/Other/random-image-api-and-public-gallery.md"};function o(s,t,l,c,n,p){return a(),d("div",null,[...t[0]||(t[0]=[r(`<h1 id="random-image-api-و-public-gallery" tabindex="-1">Random Image API و Public Gallery <a class="header-anchor" href="#random-image-api-و-public-gallery" aria-label="Permalink to &quot;Random Image API و Public Gallery&quot;">​</a></h1><p>هر دو feature از این مسیر configure می‌شوند:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API یک file تصادفی از directories انتخاب‌شده برمی‌گرداند. برای site backgrounds، avatar rotation یا random image calls از external pages مفید است.</p><p>بعد از enable شدن، استفاده کنید:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="random-image-api-settings" tabindex="-1">Random Image API Settings <a class="header-anchor" href="#random-image-api-settings" aria-label="Permalink to &quot;Random Image API Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>endpoint <code>/random</code> را on یا off می‌کند. وقتی disabled باشد، access ممنوع است.</td></tr><tr><td>Directories</td><td>مشخص می‌کند random API از کدام directories استفاده کند. directories خارج از این list توسط API استفاده نمی‌شوند.</td></tr><tr><td>Call demo</td><td>random API links قابل copy تولید می‌کند.</td></tr></tbody></table><p>می‌توانید چند directory انتخاب کنید. مثلاً اگر فقط <code>/landscape/</code> و <code>/portrait/</code> مجاز باشند، random API فقط از همان directories و subdirectories آن‌ها file انتخاب می‌کند.</p><h2 id="random-image-api-parameters" tabindex="-1">Random Image API Parameters <a class="header-anchor" href="#random-image-api-parameters" aria-label="Permalink to &quot;Random Image API Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Example</th><th>Purpose</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>random directory را مشخص می‌کند.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>media type را مشخص می‌کند. از <code>image</code>، <code>video</code>، <code>audio</code> یا ترکیب comma-separated استفاده کنید.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>image orientation را filter می‌کند. <code>portrait</code>، <code>landscape</code> یا <code>auto</code>.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>return format. خالی یعنی redirect، <code>url</code> یعنی plain text URL، <code>json</code> یعنی JSON.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>همراه <code>type=url</code> برای return کردن full URL.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>filter بر اساس age rating.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>فقط files دارای این tags را برمی‌گرداند.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>files دارای این tags را exclude می‌کند.</td></tr></tbody></table><h2 id="return-formats" tabindex="-1">Return Formats <a class="header-anchor" href="#return-formats" aria-label="Permalink to &quot;Return Formats&quot;">​</a></h2><p>بدون <code>type</code>، API مستقیم به random file URL redirect می‌کند.</p><p>با <code>type=url</code>، یک text URL برمی‌گرداند.</p><p>با <code>type=json</code>، file information شامل file URL، file ID، file name، file type، tags، rating و related metadata برمی‌گرداند.</p><h2 id="access-rules" tabindex="-1">Access Rules <a class="header-anchor" href="#access-rules" aria-label="Permalink to &quot;Access Rules&quot;">​</a></h2><p>Random Image API از public access rules پیروی می‌کند:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Directory restriction</td><td>فقط files داخل allowed directories قابل انتخاب هستند.</td></tr><tr><td>Blocklist</td><td>blocklisted files از random pool حذف می‌شوند.</td></tr><tr><td>Allowlist mode</td><td>اگر enabled باشد، فقط files مجاز برای public access برگشت داده می‌شوند.</td></tr><tr><td>Age rating</td><td>R12، R16، R18 و content مشابه بر اساس current access mode filter می‌شود.</td></tr></tbody></table><p>اگر پس از filtering هیچ fileای match نشود، API no matching result برمی‌گرداند.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API برای سرعت بهتر، directory candidate pools را cache می‌کند.</p><p>پس از تغییر files، ImgBed directory cache version را update می‌کند و requests بعدی candidate pool را دوباره build می‌کنند. empty directories برای مدت کوتاه cache می‌شوند تا repeated queries کم شود.</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>Public gallery یک صفحه public browsing فقط‌خواندنی برای directoriesی فراهم می‌کند که اجازه می‌دهید visitors ببینند.</p><p>پس از enable شدن، visitors می‌توانند باز کنند:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="public-gallery-settings" tabindex="-1">Public Gallery Settings <a class="header-anchor" href="#public-gallery-settings" aria-label="Permalink to &quot;Public Gallery Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>public gallery را on یا off می‌کند. وقتی disabled باشد، visitors نمی‌توانند آن را browse کنند.</td></tr><tr><td>Image loading mode</td><td>مشخص می‌کند previews از original images استفاده کنند یا thumbnails.</td></tr><tr><td>Open directories</td><td>مشخص می‌کند visitors به کدام directories دسترسی داشته باشند.</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th></tr></thead><tbody><tr><td>Original</td><td>visitor page، original files را مستقیم load می‌کند.</td></tr><tr><td>Thumbnail</td><td>visitor page برای سرعت بیشتر thumbnails را ترجیح می‌دهد.</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories مشخص می‌کند visitors چه چیزی ببینند.</p><p>مثال:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Visitors سپس می‌توانند access کنند:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Subdirectories هم قابل open شدن هستند، مثل <code>/2026/lucky/</code>. visitors از directories که open نیستند blocked می‌شوند.</p><h2 id="public-gallery-features" tabindex="-1">Public Gallery Features <a class="header-anchor" href="#public-gallery-features" aria-label="Permalink to &quot;Public Gallery Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Browse directories</td><td>دیدن files و subdirectories داخل open directories.</td></tr><tr><td>Search</td><td>search بر اساس file name، file ID یا tags.</td></tr><tr><td>Type filter</td><td>filter کردن images، videos، audio یا other files.</td></tr><tr><td>Tag filter</td><td>include یا exclude کردن selected tags.</td></tr><tr><td>Orientation filter</td><td>filter کردن landscape یا portrait images.</td></tr><tr><td>Time filter</td><td>filter بر اساس upload time range.</td></tr><tr><td>Extension filter</td><td>filter بر اساس file extension.</td></tr><tr><td>Copy link</td><td>copy کردن file access links.</td></tr><tr><td>Media preview</td><td>دیدن یا play کردن images، videos و audio در visitor page.</td></tr></tbody></table><h2 id="public-gallery-access-rules" tabindex="-1">Public Gallery Access Rules <a class="header-anchor" href="#public-gallery-access-rules" aria-label="Permalink to &quot;Public Gallery Access Rules&quot;">​</a></h2><p>Public gallery هم از public access rules پیروی می‌کند:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Open directories</td><td>فقط allowed directories نمایش داده می‌شوند.</td></tr><tr><td>Access mode</td><td>content بر اساس current age-rating access mode filter می‌شود.</td></tr><tr><td>Allowlist mode</td><td>اگر enabled باشد، فقط files مجاز برای public access نمایش داده می‌شوند.</td></tr><tr><td>Blocklist</td><td>blocklisted files پنهان می‌شوند.</td></tr></tbody></table>`,43)])])}const m=e(i,[["render",o]]);export{u as __pageData,m as default};
